import{c as a,Q as o,j as t,m as s}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"About Memoh","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1778736656000}'),r={name:"about.md"};function n(i,e,l,d,h,c){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="about-memoh" tabindex="-1">About Memoh <a class="header-anchor" href="#about-memoh" aria-label="Permalink to &quot;About Memoh&quot;">​</a></h1><h2 id="what-is-memoh" tabindex="-1">What Is Memoh? <a class="header-anchor" href="#what-is-memoh" aria-label="Permalink to &quot;What Is Memoh?&quot;">​</a></h2><p>Memoh is a multi-member, structured long-memory AI agent platform. You can create multiple AI bots, give each bot its own workspace and long-term memory, and interact with them through Telegram, Discord, Lark (Feishu), QQ, Matrix, Misskey, DingTalk, WeCom, WeChat, WeChat Official Account, Email, or the built-in Web UI.</p><p>Every bot has its own runtime, tools, memory configuration, channel integrations, and access policy. Depending on deployment mode, that workspace can be an isolated container or a trusted local workspace.</p><h2 id="distribution-modes" tabindex="-1">Distribution Modes <a class="header-anchor" href="#distribution-modes" aria-label="Permalink to &quot;Distribution Modes&quot;">​</a></h2><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to &quot;Desktop&quot;">​</a></h3><p>The native desktop client is for personal and local use. It starts a local <code>memoh-server</code> on <code>127.0.0.1:18731</code>, manages local SQLite storage, starts embedded Qdrant for memory search, bundles the <code>memoh</code> CLI, and owns system tray lifecycle behavior.</p><p>Desktop is the fastest way to try Memoh on your own machine.</p><h3 id="server-deploy" tabindex="-1">Server Deploy <a class="header-anchor" href="#server-deploy" aria-label="Permalink to &quot;Server Deploy&quot;">​</a></h3><p>Server Deploy is for always-on shared usage. Use it when Memoh should serve multiple users, run continuously on a server, or connect to external channels while your personal computer is offline.</p><p>The server stack can run with Docker Compose or Kubernetes and includes the backend, Web UI, database, memory services, and workspace runtime.</p><h2 id="what-makes-memoh-different" tabindex="-1">What Makes Memoh Different <a class="header-anchor" href="#what-makes-memoh-different" aria-label="Permalink to &quot;What Makes Memoh Different&quot;">​</a></h2><h3 id="multi-bot-and-multi-user" tabindex="-1">Multi-Bot And Multi-User <a class="header-anchor" href="#multi-bot-and-multi-user" aria-label="Permalink to &quot;Multi-Bot And Multi-User&quot;">​</a></h3><p>Memoh is built for real sharing and real separation at the same time:</p><ul><li>create multiple bots for different roles or people</li><li>let humans and bots interact in private chats, groups, or delegated workflows</li><li>distinguish individual users in shared conversations</li><li>bind identities across channels so the same person can be recognized consistently</li></ul><h3 id="independent-workspaces" tabindex="-1">Independent Workspaces <a class="header-anchor" href="#independent-workspaces" aria-label="Permalink to &quot;Independent Workspaces&quot;">​</a></h3><p>Each bot can use an independent workspace for files, commands, MCP hosting, and long-running tasks. Server deployments normally use container workspaces through Docker, Kubernetes, containerd, or Apple-backed runtimes. Desktop/local deployments can also use trusted local workspaces when host-level access is intentional.</p><p>Container workspaces can provide a full graphical desktop with VNC/RFB transport and a headed Chrome/Chromium browser. This enables workflows that require visible browser state rather than pure headless automation.</p><h3 id="browser-use-and-computer-use" tabindex="-1">Browser Use And Computer Use <a class="header-anchor" href="#browser-use-and-computer-use" aria-label="Permalink to &quot;Browser Use And Computer Use&quot;">​</a></h3><p>Memoh separates browser and GUI operation into practical layers:</p><ul><li><strong>Headless browser commands</strong> run as ordinary workspace commands.</li><li><strong>Browser Use</strong> operates the headed workspace browser over CDP.</li><li><strong>Computer Use</strong> drives the broader workspace desktop through screenshots, pointer input, and keyboard input.</li></ul><p>Prefer Browser Use for web pages. Use Computer Use for native dialogs, non-browser apps, or GUI states that CDP cannot reach.</p><h3 id="long-term-memory-and-context-management" tabindex="-1">Long-Term Memory And Context Management <a class="header-anchor" href="#long-term-memory-and-context-management" aria-label="Permalink to &quot;Long-Term Memory And Context Management&quot;">​</a></h3><p>Memoh separates two different problems:</p><ul><li><strong>Long-term memory</strong> stores durable facts and recalls them across conversations through memory providers</li><li><strong>Session context compaction</strong> reduces the prompt size of an active session when the current conversation gets too large</li></ul><p>This distinction is important: context compaction changes the active session window, while memory compaction rewrites stored memory entries.</p><h3 id="sessions-and-discuss-mode" tabindex="-1">Sessions And Discuss Mode <a class="header-anchor" href="#sessions-and-discuss-mode" aria-label="Permalink to &quot;Sessions And Discuss Mode&quot;">​</a></h3><p>Each bot maintains independent <strong>sessions</strong> that preserve context. Memoh currently uses five session types:</p><ul><li><strong>Chat</strong> — regular user-facing conversations</li><li><strong>Discuss</strong> — deliberative sessions where the bot can think through work and decide what to send outward</li><li><strong>Heartbeat</strong> — periodic autonomous sessions</li><li><strong>Schedule</strong> — cron-triggered task sessions</li><li><strong>Subagent</strong> — delegated task sessions</li></ul><p>You can start or route sessions with slash commands such as <code>/new</code>, and the Web UI exposes a session status panel with metrics like context usage, cache hit rate, and used skills.</p><h3 id="broad-channel-coverage" tabindex="-1">Broad Channel Coverage <a class="header-anchor" href="#broad-channel-coverage" aria-label="Permalink to &quot;Broad Channel Coverage&quot;">​</a></h3><p>Memoh uses a unified channel adapter system so one bot can be reachable from many places at once.</p><p>Current user-facing integrations include Telegram, Discord, Lark (Feishu), QQ, Matrix, Misskey, DingTalk, WeCom, WeChat, WeChat Official Account, Email, and Web.</p><h3 id="tools-skills-mcp-and-supermarket" tabindex="-1">Tools, Skills, MCP, And Supermarket <a class="header-anchor" href="#tools-skills-mcp-and-supermarket" aria-label="Permalink to &quot;Tools, Skills, MCP, And Supermarket&quot;">​</a></h3><p>Bots can use a rich set of built-in capabilities, including:</p><ul><li>web search and web fetch</li><li>workspace file editing and command execution</li><li>Browser Use and Computer Use</li><li>memory search and management</li><li>messaging, email, and TTS</li><li>subagents for delegated work</li><li><strong>skills</strong> for reusable behavior modules</li><li><strong>MCP</strong> connections for external tool servers</li><li><strong>Supermarket</strong> for curated skill and MCP template installation</li></ul><h3 id="providers-and-models" tabindex="-1">Providers And Models <a class="header-anchor" href="#providers-and-models" aria-label="Permalink to &quot;Providers And Models&quot;">​</a></h3><p>Memoh supports multiple provider client types, including OpenAI-compatible chat completions, OpenAI Responses API, Anthropic Messages, Google Generative AI, OpenAI Codex, GitHub Copilot, and Edge Speech/TTS.</p><p>Models are separated by role:</p><ul><li><strong>chat</strong> models for normal interaction</li><li><strong>embedding</strong> models for vector memory and search</li><li><strong>speech</strong> models for TTS</li></ul><p>Image generation is configured through compatible chat/image models rather than a separate image-provider system.</p><h3 id="operations-and-ui" tabindex="-1">Operations And UI <a class="header-anchor" href="#operations-and-ui" aria-label="Permalink to &quot;Operations And UI&quot;">​</a></h3><p>The Web UI is designed so you can manage the whole system without editing config files by hand every day. It includes bot configuration tabs, provider/model management, session controls, workspace files, terminal and display panes, skill management, and slash-command control from channels.</p><h2 id="where-to-start" tabindex="-1">Where To Start <a class="header-anchor" href="#where-to-start" aria-label="Permalink to &quot;Where To Start&quot;">​</a></h2><ul><li><strong><a href="/installation/">Installation Overview</a></strong> — choose Desktop or Server Deploy</li><li><strong><a href="/getting-started/provider-and-model.html">Providers And Models</a></strong> — configure model access</li><li><strong><a href="/getting-started/bot.html">Bot Setup</a></strong> — create and configure a bot</li><li><strong><a href="/getting-started/browser-computer-use.html">Browser / Computer Use</a></strong> — understand headed browser and desktop automation</li><li><strong><a href="/getting-started/channels.html">Channels</a></strong> — choose where bots are reachable</li><li><strong><a href="/getting-started/skills.html">Skills</a></strong> and <strong><a href="/getting-started/supermarket.html">Supermarket</a></strong> — extend what bots can do</li></ul>',45)])])}const p=a(r,[["render",n]]);export{u as __pageData,p as default};
